import React, { useState, useEffect } from 'react';
import { Plus, Pencil, Trash2, X, Search, ToggleLeft, ToggleRight } from 'lucide-react';
import toast from 'react-hot-toast';
import { getAllMenuItems, createMenuItem, updateMenuItem, deleteMenuItem } from '../../lib/supabase';

const CATEGORIES = ['starters', 'mains', 'noodles', 'salads', 'desserts', 'drinks'];

const EMPTY_FORM = {
  name: '', description: '', price: '', category: 'mains',
  spicy_level: 0, is_vegetarian: false, available: true, image_url: ''
};

export default function AdminMenu() {
  const [items, setItems]       = useState([]);
  const [loading, setLoading]   = useState(true);
  const [search, setSearch]     = useState('');
  const [catFilter, setCat]     = useState('all');
  const [modal, setModal]       = useState(null); // null | 'add' | 'edit'
  const [editing, setEditing]   = useState(null);
  const [form, setForm]         = useState(EMPTY_FORM);
  const [saving, setSaving]     = useState(false);

  const load = () => {
    setLoading(true);
    getAllMenuItems().then(({ data }) => {
      setItems(data || []);
      setLoading(false);
    });
  };

  useEffect(() => { load(); }, []);

  const openAdd = () => { setForm(EMPTY_FORM); setEditing(null); setModal('add'); };
  const openEdit = (item) => {
    setForm({ ...item, price: item.price.toString() });
    setEditing(item.id);
    setModal('edit');
  };
  const closeModal = () => { setModal(null); setEditing(null); setForm(EMPTY_FORM); };

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSave = async (e) => {
    e.preventDefault();
    if (!form.name || !form.price || !form.category) {
      toast.error('Name, price and category are required.');
      return;
    }
    setSaving(true);
    const payload = { ...form, price: parseFloat(form.price), spicy_level: parseInt(form.spicy_level) };
    const { error } = modal === 'add'
      ? await createMenuItem(payload)
      : await updateMenuItem(editing, payload);
    setSaving(false);
    if (error) { toast.error(error.message); return; }
    toast.success(modal === 'add' ? 'Menu item added!' : 'Menu item updated!');
    load();
    closeModal();
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete "${name}"? This cannot be undone.`)) return;
    const { error } = await deleteMenuItem(id);
    if (error) { toast.error(error.message); return; }
    toast.success('Item deleted.');
    load();
  };

  const toggleAvailability = async (item) => {
    const { error } = await updateMenuItem(item.id, { available: !item.available });
    if (error) { toast.error(error.message); return; }
    toast.success(`${item.name} ${!item.available ? 'enabled' : 'disabled'}.`);
    load();
  };

  const filtered = items.filter(i => {
    const matchCat    = catFilter === 'all' || i.category === catFilter;
    const matchSearch = i.name.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  return (
    <div>
      <div className="admin-section-head">
        <div>
          <h2>Menu Items</h2>
          <p>{items.length} total items · {items.filter(i => i.available).length} active</p>
        </div>
        <button className="btn btn-primary" onClick={openAdd}>
          <Plus size={15} /> Add Item
        </button>
      </div>

      {/* Filters */}
      <div className="admin-filter-bar">
        <div className="admin-search">
          <Search size={14} className="admin-search__icon" />
          <input placeholder="Search menu items..." value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <select className="form-input" style={{ width:'auto' }} value={catFilter} onChange={e => setCat(e.target.value)}>
          <option value="all">All Categories</option>
          {CATEGORIES.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
        </select>
      </div>

      {loading ? <div className="spinner" /> : (
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Category</th>
                <th>Price</th>
                <th>Spicy</th>
                <th>Veg</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr><td colSpan={7} style={{ textAlign:'center', padding:'40px', color:'var(--text-muted)', fontStyle:'italic' }}>No items found.</td></tr>
              ) : filtered.map(item => (
                <tr key={item.id}>
                  <td>
                    <div style={{ fontWeight:500 }}>{item.name}</div>
                    <div style={{ fontSize:11, color:'var(--text-muted)', marginTop:2 }}>{(item.description||'').slice(0,50)}{item.description?.length > 50 ? '…' : ''}</div>
                  </td>
                  <td style={{ textTransform:'capitalize' }}>{item.category}</td>
                  <td style={{ fontWeight:600, color:'var(--amber-dark)' }}>${parseFloat(item.price).toFixed(2)}</td>
                  <td>{'🌶'.repeat(item.spicy_level) || '—'}</td>
                  <td>{item.is_vegetarian ? '🌿' : '—'}</td>
                  <td>
                    <button onClick={() => toggleAvailability(item)} style={{ display:'flex', alignItems:'center', gap:5, fontSize:12, color: item.available ? 'var(--jade-dark)' : 'var(--text-muted)' }}>
                      {item.available ? <ToggleRight size={18} color="var(--jade)" /> : <ToggleLeft size={18} />}
                      {item.available ? 'Active' : 'Hidden'}
                    </button>
                  </td>
                  <td>
                    <div style={{ display:'flex', gap:6 }}>
                      <button className="admin-action-btn admin-action-btn--edit" onClick={() => openEdit(item)}>
                        <Pencil size={12} /> Edit
                      </button>
                      <button className="admin-action-btn admin-action-btn--delete" onClick={() => handleDelete(item.id, item.name)}>
                        <Trash2 size={12} /> Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Modal */}
      {modal && (
        <div className="admin-modal-overlay">
          <div className="admin-modal">
            <div className="admin-modal__header">
              <h3>{modal === 'add' ? 'Add Menu Item' : 'Edit Menu Item'}</h3>
              <button className="admin-modal__close" onClick={closeModal}><X size={18} /></button>
            </div>
            <form onSubmit={handleSave}>
              <div className="admin-modal__body">
                <div className="admin-form-grid">
                  <div className="form-group full">
                    <label>Item Name *</label>
                    <input required className="form-input" placeholder="e.g. Ohn No Khao Swe"
                      value={form.name} onChange={e => set('name', e.target.value)} />
                  </div>
                  <div className="form-group full">
                    <label>Description</label>
                    <textarea className="form-input" placeholder="Describe the dish..."
                      value={form.description} onChange={e => set('description', e.target.value)} />
                  </div>
                  <div className="form-group">
                    <label>Price ($) *</label>
                    <input required type="number" step="0.01" min="0" className="form-input" placeholder="0.00"
                      value={form.price} onChange={e => set('price', e.target.value)} />
                  </div>
                  <div className="form-group">
                    <label>Category *</label>
                    <select required className="form-input" value={form.category} onChange={e => set('category', e.target.value)}>
                      {CATEGORIES.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Spicy Level (0–3)</label>
                    <select className="form-input" value={form.spicy_level} onChange={e => set('spicy_level', e.target.value)}>
                      <option value={0}>0 — Not spicy</option>
                      <option value={1}>1 — Mild 🌶</option>
                      <option value={2}>2 — Medium 🌶🌶</option>
                      <option value={3}>3 — Hot 🌶🌶🌶</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Image URL</label>
                    <input className="form-input" placeholder="https://..."
                      value={form.image_url} onChange={e => set('image_url', e.target.value)} />
                  </div>
                  <div className="form-group" style={{ flexDirection:'row', alignItems:'center', gap:10, paddingTop:8 }}>
                    <input type="checkbox" id="veg" checked={form.is_vegetarian} onChange={e => set('is_vegetarian', e.target.checked)} />
                    <label htmlFor="veg" style={{ marginBottom:0, cursor:'pointer' }}>Vegetarian</label>
                  </div>
                  <div className="form-group" style={{ flexDirection:'row', alignItems:'center', gap:10, paddingTop:8 }}>
                    <input type="checkbox" id="avail" checked={form.available} onChange={e => set('available', e.target.checked)} />
                    <label htmlFor="avail" style={{ marginBottom:0, cursor:'pointer' }}>Available on menu</label>
                  </div>
                </div>
              </div>
              <div className="admin-modal__footer">
                <button type="button" className="btn btn-outline" onClick={closeModal}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  {saving ? 'Saving...' : modal === 'add' ? 'Add Item' : 'Save Changes'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
